func snapshotEWFlag(f *EWFlag) ewFlagSnapshot {
	f.mu.RLock()
	defer f.mu.RUnlock()

	dots := make(map[string]uint64, len(f.dots))
	for nodeID, counter := range f.dots {
		dots[nodeID] = counter
	}
	counters := make(map[string]uint64, len(f.counters))
	for nodeID, counter := range f.counters {
		counters[nodeID] = counter
	}
	return ewFlagSnapshot{
		dots:     dots,
		counters: counters,
		enabled:  len(dots) > 0,
	}
}

func concurrentEnableAndEmptyDisable() (*EWFlag, *EWFlag) {
	enabled := NewEWFlag()
