	return enabled, disabled
}

func observedDisableAndStaleEnable() (*EWFlag, *EWFlag) {
	enabled := NewEWFlag()
	enabled.Enable("node-a")

	disabled := NewEWFlag()
	disabled.Merge(enabled)
	disabled.Disable()

	return enabled, disabled
